class Solution {
public:
    int maxValue(int n, int index, int maxSum) {
        int left = index, right = n - index - 1;
        int l = 1, r = maxSum;
        while (l <= r) {
            int mid = l + (r - l) / 2;
            long long sum = (long long)mid + calc(left, mid) + calc(right, mid) - 1;
            if (sum <= maxSum) l = mid + 1;
            else r = mid - 1;
        }
        return r;
    }

    long long calc(int n, int m) {
        if (n >= m - 1) return (long long)m * (m + 1) / 2 + (long long)(n - m + 1);
        else return (long long)(m + m - n) * (n + 1) / 2;
    }
};
